mapper.select:
SELECT C.company_id , C.company_code , C.company_name , CC.company_checkup_id , CC.checkup_year , CCT.company_checkup_type_id , CCT.company_checkup_type_code , CCT.company_checkup_type_name , CTR_LIST.checkup_contract_id , CTR_LIST.hospital_id , CTR_LIST.center_id , CONTT.checkup_contract_type_id , IF(CONTT.checkup_contract_type_id IS NULL, 0, 1) AS register FROM company C JOIN company_checkup CC ON CC.company_id = C.company_id AND CC.deleted_at IS NULL JOIN company_checkup_type CCT ON CC.company_checkup_id = CCT.company_checkup_id AND CCT.deleted_at IS NULL LEFT JOIN (SELECT DISTINCT checkup_contract.company_checkup_id, checkup_contract.checkup_contract_id, checkup_contract.hospital_id, checkup_contract_type.center_id FROM checkup_contract JOIN checkup_contract_type ON checkup_contract.checkup_contract_id = checkup_contract_type.checkup_contract_id) CTR_LIST ON CC.company_checkup_id = CTR_LIST.company_checkup_id LEFT JOIN checkup_contract CONT ON CC.company_checkup_id = CONT.company_checkup_id AND CTR_LIST.hospital_id = CONT.hospital_id AND CTR_LIST.company_checkup_id = CONT.company_checkup_id LEFT JOIN checkup_contract_type CONTT ON CCT.company_checkup_type_id = CONTT.company_checkup_type_id AND CONT.checkup_contract_id = CONTT.checkup_contract_id AND CTR_LIST.center_id = CONTT.center_id LEFT JOIN center ON CTR_LIST.center_id = center.center_id LEFT JOIN hospital ON CTR_LIST.hospital_id = hospital.hospital_id WHERE C.deleted_at IS NULL AND CC.checkup_year = #{checkupYear}
AND C.company_id = #{companyId}
ORDER BY C.company_name, hospital.hospital_name, center.center_name, CCT.company_checkup_type_code

