INSERT INTO checkup_contract_item
        ( checkup_contract_sub_type_id
        , item_id
        , checkup_contract_item_memo
        , register
        , copay
        , discount_bill
        , created_user_id
        , updated_user_id)
VALUES ( #{checkupContractSubTypeId}
       , #{id}
       , #{checkupContractItemMemo}
       , #{register}
       , #{copay}
       , #{discountBill}
       , #{sessionUserId}
       , #{sessionUserId})
ON DUPLICATE KEY UPDATE checkup_contract_item_memo = #{checkupContractItemMemo}
                      , register                   = #{register}
                      , copay                      = #{copay}
                      , discount_bill              = #{discountBill}
                      , updated_at                 = NOW()
                      , updated_user_id            = #{sessionUserId}
